import { Component, Host, Prop, State, Watch, h } from '@stencil/core';
import { Booking } from '@/models/booking.dto';
import { IEntries } from '@/models/IBooking';
import { CityLedgerService } from '@/services/city-ledger';
import type { ServiceCategoryOption } from '@/components/ir-city-ledger/ir-city-ledger-folio/ir-city-ledger-transaction-drawer/ir-city-ledger-transaction-form/ir-city-ledger-transaction-form.schema';
import { mapClTxToFolioRow, FolioRow } from '@/components/ir-city-ledger/ir-city-ledger-folio/types';
import moment from 'moment';
import calendar_data from '@/stores/calendar-data';
import Token from '@/models/Token';
import { actionableClTypes } from '@/services/city-ledger.service';
import { formatAmount } from '@/utils/utils';

@Component({
  tag: 'ir-booking-city-ledger',
  styleUrls: ['ir-booking-city-ledger.css', '../../../common/table.css'],
  scoped: true,
})
export class IrBookingCityLedger {
  private cityLedgerService = new CityLedgerService();
  private tokenService = new Token();

  /** Booking object; component is hidden when booking.agent is null. */
  @Prop() booking: Booking;

  /** Active language code. */
  @Prop() language: string = 'en';

  /** Service-category entries used to populate the transaction form. */
  @Prop() svcCategories: IEntries[] = [];

  @State() private isLoading: boolean = false;
  @State() private folioRows: FolioRow[] = [];
  @State() private drawerOpen: boolean = false;
  @State() private error: string | null = null;
  @State() private deleteTarget: FolioRow | null = null;
  @State() private isDeleting: boolean = false;
  @State() private editingRow: FolioRow | null = null;

  componentWillLoad() {
    if (this.booking?.agent) {
      this.fetchCityLedger();
    }
  }

  @Watch('booking')
  handleBookingChange(newVal: Booking, oldVal: Booking) {
    const agentChanged = newVal?.agent?.id !== oldVal?.agent?.id;
    const datesChanged = newVal?.from_date !== oldVal?.from_date || newVal?.to_date !== oldVal?.to_date;
    if (newVal?.agent && (agentChanged || datesChanged)) {
      this.fetchCityLedger();
    }
  }

  private async fetchCityLedger() {
    if (!this.booking?.agent) return;
    this.isLoading = true;
    this.error = null;
    try {
      const result = await this.cityLedgerService.fetchCL({
        AGENCY_ID: this.booking.agent.id,
        START_DATE: this.booking.from_date,
        END_DATE: this.booking.to_date,
        START_ROW: 0,
        END_ROW: 200,
        SEARCH_QUERY: this.booking.booking_nbr,
      });
      let runningBalance = 0;
      this.folioRows = result.My_Cl_tx.map((tx, i) => {
        runningBalance = runningBalance + tx.DEBIT - tx.CREDIT;
        return { _rowId: String(i), ...mapClTxToFolioRow(tx), balance: runningBalance };
      });
    } catch (err) {
      console.error('[ir-booking-city-ledger] fetchCL failed:', err);
      this.error = 'Failed to load city ledger.';
    } finally {
      this.isLoading = false;
    }
  }

  private async handleDelete() {
    const row = this.deleteTarget;
    if (!row) return;
    this.isDeleting = true;
    try {
      await this.cityLedgerService.issueManualCLTx({
        CL_TX_ID: row._raw.CL_TX_ID,
        AGENCY_ID: this.booking.agent.id,
        SERVICE_DATE: row._raw.SERVICE_DATE,
        CL_TX_TYPE_CODE: row._raw.CL_TX_TYPE_CODE ?? '',
        DESCRIPTION: row._raw.DESCRIPTION,
        DEBIT: row._raw.DEBIT,
        CREDIT: row._raw.CREDIT,
        CURRENCY_ID: row._raw.CURRENCY_ID,
        PAY_METHOD_CODE: row._raw.PAY_METHOD_CODE ?? '',
        EXTERNAL_REF: row._raw.EXTERNAL_REF ?? '',
        IS_DELETE: true,
      });
      this.deleteTarget = null;
      await this.fetchCityLedger();
    } catch (err) {
      console.error('[ir-booking-city-ledger] delete failed:', err);
    } finally {
      this.isDeleting = false;
    }
  }

  private get serviceCategoryOptions(): ServiceCategoryOption[] {
    return this.svcCategories.map(s => ({ id: s.CODE_NAME, label: s.CODE_VALUE_EN }));
  }

  private get bookingOptions() {
    return this.booking?.booking_nbr ? [{ id: this.booking.booking_nbr, label: `#${this.booking.booking_nbr}` }] : [];
  }

  private formatAmount(value: number): string {
    if (!value) return '—';
    return formatAmount(calendar_data.property?.currency?.symbol, value);
  }

  private renderTable() {
    if (this.folioRows.length === 0) {
      return <ir-empty-state></ir-empty-state>;
    }
    return (
      <div class="table--container booking-city-ledger__table-wrap">
        <table class="table data-table">
          <thead>
            <tr>
              <th>Status</th>
              <th>Date</th>
              <th class="booking-city-ledger__cell-desc">Description</th>
              <th class="text-right">Amount</th>
              <th></th>
              {/* <th class="text-right">Credit</th> */}
              {/* <th class="text-right">Balance</th> */}
            </tr>
          </thead>
          <tbody>
            {this.folioRows.map(row => (
              <tr key={row._rowId} class="ir-table-row">
                <td>
                  <wa-tag size="small" variant={row.status.variant as any}>
                    {row.status.label}
                    {row.status.id === 'billed' && <wa-icon name="lock"></wa-icon>}
                  </wa-tag>
                </td>
                <td class="booking-city-ledger__cell-date">{moment(row.serviceDate).format('MMM DD, YYYY')}</td>
                <td class="booking-city-ledger__cell-desc">{row.description || '—'}</td>

                <td class="text-right ">
                  {row.debit !== null && <span class={'is-debit'}>{row.debit ? this.formatAmount(row.debit) : ''}</span>}
                  {row.credit !== null && <span class={'is-credit'}>{row.credit ? this.formatAmount(row.credit) : ''}</span>}
                </td>
                <td>
                  {row.status.id !== 'billed' && row._raw.CATEGORY === null && actionableClTypes.has(row._raw.CL_TX_TYPE_CODE as any) && (
                    <wa-dropdown
                      onwa-hide={e => {
                        e.stopImmediatePropagation();
                        e.stopPropagation();
                      }}
                      onwa-select={e => {
                        switch ((e.detail as any).item.value) {
                          case 'edit':
                            this.editingRow = row;
                            this.drawerOpen = true;
                            break;
                          case 'delete':
                            this.deleteTarget = row;
                            break;
                        }
                      }}
                    >
                      <div slot="trigger">
                        <ir-custom-button appearance="plain">
                          <wa-icon name="ellipsis-vertical"></wa-icon>
                        </ir-custom-button>
                      </div>
                      <wa-dropdown-item value="edit">
                        <wa-icon slot="icon" name="edit"></wa-icon>
                        Edit
                      </wa-dropdown-item>
                      <wa-dropdown-item value="delete" variant="danger">
                        <wa-icon slot="icon" name="trash"></wa-icon>
                        Delete
                      </wa-dropdown-item>
                    </wa-dropdown>
                  )}
                </td>
                {/* <td class="text-right is-credit">{row.credit ? this.formatAmount(row.credit) : '—'}</td> */}
                {/* <td class="text-right">{this.formatAmount(row.balance)}</td> */}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  }

  render() {
    if (!this.booking?.agent) {
      return <Host></Host>;
    }
    return (
      <Host>
        <wa-card class="booking-city-ledger__card">
          <div slot="header" class="booking-city-ledger__header-title">
            <p class="font-size-large p-0 m-0"> Agent Folio</p>
          </div>

          <wa-tooltip for="booking-city-ledger-add-btn">Add folio entry</wa-tooltip>
          <ir-custom-button
            slot="header-actions"
            id="booking-city-ledger-add-btn"
            size="small"
            variant="neutral"
            appearance="plain"
            onClickHandler={() => {
              this.editingRow = null;
              this.drawerOpen = true;
            }}
          >
            <wa-icon name="plus" style={{ fontSize: '1rem' }}></wa-icon>
          </ir-custom-button>

          {this.isLoading ? (
            <div class="booking-city-ledger__spinner-wrap">
              <ir-spinner></ir-spinner>
            </div>
          ) : this.error ? (
            <p class="booking-city-ledger__error">{this.error}</p>
          ) : (
            this.renderTable()
          )}
        </wa-card>

        <ir-city-ledger-transaction-drawer
          open={this.drawerOpen}
          drawerLabel={this.editingRow ? 'Edit Folio Entry' : 'New Folio Entry'}
          agent={this.booking.agent}
          booking={this.booking}
          transaction={this.editingRow?._raw ?? null}
          serviceCategoryOptions={this.serviceCategoryOptions}
          bookingOptions={this.bookingOptions}
          onCloseDrawer={() => {
            this.drawerOpen = false;
            this.editingRow = null;
          }}
          onTransactionSaved={async () => {
            this.drawerOpen = false;
            this.editingRow = null;
            await this.fetchCityLedger();
          }}
        ></ir-city-ledger-transaction-drawer>
        <ir-cl-fiscal-document-preview ticket={this.tokenService.getToken()} propertyId={calendar_data?.property?.id}></ir-cl-fiscal-document-preview>

        <ir-dialog
          label="Delete Entry"
          open={!!this.deleteTarget}
          onIrDialogHide={e => {
            e.stopImmediatePropagation();
            e.stopPropagation();
            if (!this.isDeleting) this.deleteTarget = null;
          }}
        >
          <p>Are you sure you want to delete this entry? This action cannot be undone.</p>
          <div slot="footer" class="ir-dialog__footer">
            <ir-custom-button size="medium" appearance="filled" variant="neutral" onClickHandler={() => (this.deleteTarget = null)}>
              Cancel
            </ir-custom-button>
            <ir-custom-button size="medium" variant="danger" loading={this.isDeleting} onClickHandler={() => this.handleDelete()}>
              Delete
            </ir-custom-button>
          </div>
        </ir-dialog>
      </Host>
    );
  }
}
